import{_ as e,c as t,o,a4 as a}from"./chunks/framework.nQaBHiNx.js";const m=JSON.parse('{"title":"网络是怎样连接的","description":"","frontmatter":{},"headers":[],"relativePath":"computer/book/how-the-network-connect/index.md","filePath":"computer/book/how-the-network-connect/index.md"}'),r={name:"computer/book/how-the-network-connect/index.md"},n=a('<h1 id="网络是怎样连接的" tabindex="-1">网络是怎样连接的 <a class="header-anchor" href="#网络是怎样连接的" aria-label="Permalink to &quot;网络是怎样连接的&quot;">​</a></h1><p>本书以探索之旅的形式，从在浏览器中输入网址开始，一路追踪了到显示出网页内容为止的整个过程，以图配文，讲解了网络的全貌，并重点介绍了实际的网络设备和软件是如何工作的。目的是帮助读者理解网络的本质意义，理解实际的设备和软件，进而熟练运用网络技术。同时，专设了“网络术语其实很简单”专栏，以对话的形式介绍了一些网络术语的词源，颇为生动有趣。</p><p>本书图文并茂，通俗易懂，非常适合计算机、网络爱好者及相关从业人员阅读。</p><ul><li>第一章　浏览器生成消息</li><li>第二章　用电信号传输 TCP/IP 数据</li><li>第三章　从网线到网络设备</li><li>第四章　通过接入网进入互联网内部</li><li>第五章　服务器端的局域网中有什么玄机</li><li>第六章　请求到达 Web 服务器，响应返回浏览器</li></ul><h2 id="学习资料" tabindex="-1">学习资料 <a class="header-anchor" href="#学习资料" aria-label="Permalink to &quot;学习资料&quot;">​</a></h2><p><a href="https://book.douban.com/subject/26941639/" target="_blank" rel="noreferrer">豆瓣读书 - 网络是怎样连接的 - [日]户根勤</a></p>',6),i=[n];function c(l,_,s,d,h,p){return o(),t("div",null,i)}const b=e(r,[["render",c]]);export{m as __pageData,b as default};
